// ═══════════════════════════════════════════════════════════
// Main Simulation Engine
// ═══════════════════════════════════════════════════════════
//
// Manages the game clock and drives the object engine + characters.
// Ticks at configurable intervals (~5 seconds default).
// Provides start/stop/pause controls and an event bus.

import { ObjectEngine } from './objects.js';
import { OBJECT_DEFS, SECTORS, WORLD_TREE } from './world.js';
import { Character, CHARACTER_DEFS, isWalkable } from './characters.js';
import { MAP_COLS } from './tilemap.js';

export class SimulationEngine {
  constructor(options = {}) {
    this.tickIntervalMs = options.tickIntervalMs ?? 5000; // ~5 seconds
    this.timeScale = options.timeScale ?? 1;              // speed multiplier

    this.objectEngine = new ObjectEngine();
    this.running = false;
    this.paused = false;
    this.elapsedMs = 0;         // total simulation time
    this.tickCount = 0;
    this.listeners = new Map();  // event type → Set<callback>

    this._rafId = null;
    this._lastTimestamp = null;
    this._accumulator = 0;       // accumulated time toward next tick

    // Load world
    this.objectEngine.addObjects(OBJECT_DEFS);
    this.sectors = SECTORS;
    this.worldTree = WORLD_TREE;

    // Load characters
    this.characters = CHARACTER_DEFS.map(def => new Character(def));

    // AI integration
    this.aiEngine = options.aiEngine || null;
    this.aiMode = false;

    // Simulated clock — starts at 8:00 AM on Day 1
    // Each tick advances 5 sim-minutes → 1 sim-day per ~24 real minutes at 1x
    this.simClock = {
      day: 1,
      minuteOfDay: 480,
      simMinutesPerTick: 5,
      get hour() { return Math.floor(this.minuteOfDay / 60); },
      get minute() { return Math.floor(this.minuteOfDay % 60); },
      get timeString() {
        const h = this.hour;
        const m = this.minute;
        const period = h >= 12 ? 'PM' : 'AM';
        const h12 = h % 12 || 12;
        return `${h12}:${String(m).padStart(2, '0')} ${period}`;
      },
      get dayTimeString() {
        return `Day ${this.day} \u2014 ${this.timeString}`;
      },
      advance() {
        this.minuteOfDay += this.simMinutesPerTick;
        while (this.minuteOfDay >= 1440) {
          this.minuteOfDay -= 1440;
          this.day++;
        }
      },
    };

    // Last notable event for the status bar
    this.lastStatusText = '';

    // Forward object events to our bus
    this.objectEngine.onTransition((event) => {
      this._emit('object:transition', event);
      this._reactToObjectEvent(event);
    });

    // Attach AI engine
    if (this.aiEngine) {
      this.aiEngine.attach(this);
    }
  }

  start() {
    if (this.running) return;
    this.running = true;
    this.paused = false;
    this._lastTimestamp = performance.now();
    this._accumulator = 0;
    this._emit('engine:start', { elapsedMs: this.elapsedMs });
    this._loop();
  }

  stop() {
    this.running = false;
    this.paused = false;
    if (this._rafId) {
      cancelAnimationFrame(this._rafId);
      this._rafId = null;
    }
    this._emit('engine:stop', { elapsedMs: this.elapsedMs, tickCount: this.tickCount });
  }

  pause() {
    if (!this.running) return;
    this.paused = true;
    this._emit('engine:pause', { elapsedMs: this.elapsedMs });
  }

  resume() {
    if (!this.running || !this.paused) return;
    this.paused = false;
    this._lastTimestamp = performance.now();
    this._emit('engine:resume', { elapsedMs: this.elapsedMs });
  }

  // Manually advance by a number of ticks (useful for testing)
  manualTick(count = 1) {
    const events = [];
    for (let i = 0; i < count; i++) {
      const tickEvents = this.objectEngine.tick(this.tickIntervalMs);
      this.tickCount++;
      this.elapsedMs += this.tickIntervalMs;
      this._wanderTick();
      this._updateCharacters(this.tickIntervalMs);
      events.push(...tickEvents);
    }
    this._emit('engine:tick', {
      tickCount: this.tickCount,
      elapsedMs: this.elapsedMs,
      events,
    });
    return events;
  }

  // Interact with an object (character-triggered)
  interact(objectId, action = 'use') {
    return this.objectEngine.interact(objectId, action);
  }

  // Get object by id
  getObject(objectId) {
    return this.objectEngine.get(objectId);
  }

  // Get all objects
  getAllObjects() {
    return this.objectEngine.getAll();
  }

  // Get objects in a sector
  getObjectsInSector(sector) {
    return this.objectEngine.getBySector(sector);
  }

  // Get all characters
  getCharacters() {
    return this.characters;
  }

  // Full state snapshot
  snapshot() {
    return {
      running: this.running,
      paused: this.paused,
      elapsedMs: this.elapsedMs,
      tickCount: this.tickCount,
      tickIntervalMs: this.tickIntervalMs,
      timeScale: this.timeScale,
      aiMode: this.aiMode,
      simClock: { day: this.simClock.day, time: this.simClock.timeString },
      objects: this.objectEngine.snapshot(),
      characters: this.characters.map(c => ({
        id: c.id, name: c.name, tx: c.tx, ty: c.ty,
        action: c.action, facing: c.facing, mood: c.mood,
        targetObjectId: c.targetObjectId,
      })),
    };
  }

  // ── Event bus ──

  on(eventType, callback) {
    if (!this.listeners.has(eventType)) {
      this.listeners.set(eventType, new Set());
    }
    this.listeners.get(eventType).add(callback);
    return () => this.off(eventType, callback);
  }

  off(eventType, callback) {
    this.listeners.get(eventType)?.delete(callback);
  }

  _emit(eventType, data) {
    const callbacks = this.listeners.get(eventType);
    if (callbacks) {
      for (const cb of callbacks) {
        cb(data);
      }
    }
    // Also emit wildcard
    const wildcards = this.listeners.get('*');
    if (wildcards) {
      for (const cb of wildcards) {
        cb({ type: eventType, ...data });
      }
    }
  }

  // ── Character AI / Wander behavior ──

  _wanderTick() {
    // Advance simulated clock each tick
    this.simClock.advance();

    for (const char of this.characters) {
      if (char.action !== 'idle') continue;

      // AI mode: delegate to AI decision engine
      if (this.aiMode && this.aiEngine) {
        if (!this.aiEngine.isPending(char.id)) {
          this.aiEngine.tick(char, this.tickIntervalMs);
        }
        continue;
      }

      // Random wander with cooldown
      char.wanderCooldown -= this.tickIntervalMs;
      if (char.wanderCooldown > 0) continue;

      // Priority actions first (reactive behavior), then random wander
      const priority = this._getPriorityTarget(char);
      const target = priority ? priority.obj : this._pickWanderTarget(char);
      const action = priority ? priority.action : 'use';

      if (!target) {
        char.wanderCooldown = 5000;
        continue;
      }

      const tile = findInteractTile(target.position);
      if (!tile) {
        char.wanderCooldown = 5000;
        continue;
      }

      // Already adjacent — interact directly
      const atTarget = tile.tx === Math.round(char.tx) && tile.ty === Math.round(char.ty);
      if (atTarget) {
        this._doInteraction(char, target, action);
        char.wanderCooldown = 30000 + Math.random() * 30000;
      } else if (char.moveTo(tile.tx, tile.ty)) {
        char.targetObjectId = target.id;
        char.pendingAction = action;
        char.wanderCooldown = 30000 + Math.random() * 30000;
      } else {
        char.wanderCooldown = 5000;
      }
    }
  }

  /** Immediate random wander (no cooldown) — used as AI fallback. */
  _randomWander(char) {
    const priority = this._getPriorityTarget(char);
    const target = priority ? priority.obj : this._pickWanderTarget(char);
    const action = priority ? priority.action : 'use';

    if (!target) return;

    const tile = findInteractTile(target.position);
    if (!tile) return;

    const atTarget = tile.tx === Math.round(char.tx) && tile.ty === Math.round(char.ty);
    if (atTarget) {
      this._doInteraction(char, target, action);
    } else if (char.moveTo(tile.tx, tile.ty)) {
      char.targetObjectId = target.id;
      char.pendingAction = action;
    }
  }

  _updateCharacters(deltaMs) {
    for (const char of this.characters) {
      const wasWalking = char.action === 'walking';
      char.update(deltaMs);

      // Character just arrived at destination
      if (wasWalking && char.action === 'idle') {
        if (char.targetObjectId) {
          const obj = this.objectEngine.get(char.targetObjectId);
          if (obj) {
            this._doInteraction(char, obj, char.pendingAction || 'use');
          } else {
            char.targetObjectId = null;
          }
          char.pendingAction = 'use';
        } else if (char.targetCharId) {
          // Character arrived near another character for conversation — face each other
          const target = this.characters.find(c => c.id === char.targetCharId);
          if (target) {
            char._updateFacing(target.tx - char.tx, target.ty - char.ty);
            target._updateFacing(char.tx - target.tx, char.ty - target.ty);
          }
          char.targetCharId = null;
        }
      }
    }
  }

  // ── Object → interaction animation mapping ──
  // Maps object ID substrings to the animation played during interaction.
  static _getInteractAnim(objectId) {
    if (!objectId) return null;
    if (objectId.includes('book') || objectId.includes('desk') || objectId.includes('bookshelf')) {
      return 'reading';
    }
    if (objectId.includes('bed') || objectId.includes('kotatsu') || objectId.includes('sofa') || objectId.includes('tv')) {
      return 'sit';
    }
    // phone / general interaction fallback for everything else
    return 'phone';
  }

  _doInteraction(char, obj, action = 'use') {
    // Face toward the object
    const objCx = obj.position.tx + (obj.position.tw || 1) / 2;
    const objCy = obj.position.ty + (obj.position.th || 1) / 2;
    const dx = objCx - char.tx;
    const dy = objCy - char.ty;
    if (Math.abs(dx) >= Math.abs(dy)) {
      char._updateFacing(dx, 0);
    } else {
      char._updateFacing(0, dy);
    }

    const event = this.objectEngine.interact(obj.id, action);
    if (event) {
      const anim = SimulationEngine._getInteractAnim(obj.id);
      char.startInteraction(obj.id, anim);

      // Successful interaction → happy (unless already upset)
      if (char.mood !== 'upset') {
        char.setMood('happy', 5000);
      }

      this._emit('character:interact', {
        characterId: char.id, characterName: char.name,
        objectId: obj.id, objectName: event.objectName,
        from: event.from, to: event.to,
        produces: event.produces || null,
        emoji: event.emoji || null,
      });
    } else {
      char.targetObjectId = null;
    }
  }

  // ── Collision helpers ──

  /** Returns a Set of tile keys (ty*MAP_COLS+tx) for all characters except `exceptChar`. */
  _getOccupiedTiles(exceptChar) {
    const tiles = new Set();
    for (const c of this.characters) {
      if (c === exceptChar) continue;
      tiles.add(c.ty * MAP_COLS + c.tx);
    }
    return tiles;
  }

  /** Like char.moveTo but marks other characters' tiles as unwalkable during A*. */
  _moveCharWithCollision(char, goalTx, goalTy) {
    const blocked = this._getOccupiedTiles(char);
    return char.moveTo(goalTx, goalTy, blocked);
  }

  /** Like findInteractTile but prefers tiles not currently occupied by other characters. */
  _findFreeInteractTile(objPosition, char) {
    const { tx, ty, tw = 1, th = 1 } = objPosition;
    const occupied = this._getOccupiedTiles(char);
    const free = [];
    const all = [];

    const addCandidate = (x, y) => {
      if (!isWalkable(x, y)) return;
      const entry = { tx: x, ty: y };
      all.push(entry);
      if (!occupied.has(y * MAP_COLS + x)) free.push(entry);
    };

    for (let x = tx - 1; x <= tx + tw; x++) {
      addCandidate(x, ty - 1);
      addCandidate(x, ty + th);
    }
    for (let y = ty; y < ty + th; y++) {
      addCandidate(tx - 1, y);
      addCandidate(tx + tw, y);
    }

    const pool = free.length > 0 ? free : all;
    if (pool.length === 0) return null;
    return pool[Math.floor(Math.random() * pool.length)];
  }

  /**
   * Deadlock escape: move to a random free adjacent tile so the character
   * can re-path around whatever is blocking them. _pendingTarget is preserved
   * so the arrival handler knows to re-path to the original goal.
   */
  _deadlockEscape(char) {
    const DIRS = [[0, -1], [0, 1], [-1, 0], [1, 0]];
    const occupied = this._getOccupiedTiles(char);
    // Shuffle directions for variety
    const dirs = DIRS.slice().sort(() => Math.random() - 0.5);
    for (const [dx, dy] of dirs) {
      const nx = char.tx + dx;
      const ny = char.ty + dy;
      if (isWalkable(nx, ny) && !occupied.has(ny * MAP_COLS + nx)) {
        // Move one tile — _pendingTarget stays set; arrival handler will re-path
        char.moveTo(nx, ny);
        return;
      }
    }
    // Completely surrounded — give up
    char._pendingTarget = null;
    char._retryCount = 0;
  }

  _getPriorityTarget(char) {
    // Sol: pick up book if closed and nearby
    if (char.id === 'sol') {
      const book = this.objectEngine.get('cafe_book');
      if (book && book.state === 'closed') {
        const dist = Math.abs(book.position.tx - char.tx) + Math.abs(book.position.ty - char.ty);
        if (dist <= 6) {
          return { obj: book, action: 'use' };
        }
      }
    }

    // Non-Maple near stocked display → take pastry
    if (char.id !== 'maple') {
      const display = this.objectEngine.get('cafe_display');
      if (display && display.state === 'stocked') {
        const dist = Math.abs(display.position.tx - char.tx) + Math.abs(display.position.ty - char.ty);
        if (dist <= 8) {
          return { obj: display, action: 'use' };
        }
      }
    }

    // Maple: restock empty display case
    if (char.id === 'maple') {
      const display = this.objectEngine.get('cafe_display');
      if (display && display.state === 'empty') {
        return { obj: display, action: 'use' };
      }
    }

    return null;
  }

  _pickWanderTarget(char) {
    const allObjects = this.objectEngine.getAll();

    // 60% home sector, 40% any sector
    let candidates;
    if (Math.random() < 0.6) {
      candidates = allObjects.filter(o => o.sector === char.homeSector);
      if (candidates.length === 0) candidates = allObjects;
    } else {
      candidates = allObjects;
    }

    // Avoid repeating last interaction
    if (char.lastObjectId && candidates.length > 1) {
      candidates = candidates.filter(o => o.id !== char.lastObjectId);
    }

    if (candidates.length === 0) return null;
    return candidates[Math.floor(Math.random() * candidates.length)];
  }

  _reactToObjectEvent(event) {
    // Espresso done → Maple happy
    if (event.objectId === 'cafe_espresso' && event.to === 'done') {
      const maple = this.characters.find(c => c.id === 'maple');
      if (maple) maple.setMood('happy', 10000);
    }

    // Easel finished → Nyx happy
    if (event.objectId === 'apt_easel' && event.to === 'finished') {
      const nyx = this.characters.find(c => c.id === 'nyx');
      if (nyx) nyx.setMood('happy', 20000);
    }

    // Display restocked → nearby characters happy
    if (event.objectId === 'cafe_display' && event.to === 'stocked') {
      for (const char of this.characters) {
        const display = this.objectEngine.get('cafe_display');
        if (display) {
          const dist = Math.abs(display.position.tx - char.tx) + Math.abs(display.position.ty - char.ty);
          if (dist <= 6) char.setMood('happy', 10000);
        }
      }
    }
  }

  // ── Internal loop ──

  _loop() {
    if (!this.running) return;

    this._rafId = requestAnimationFrame((timestamp) => {
      if (!this.running) return;

      if (!this.paused) {
        const rawDelta = timestamp - this._lastTimestamp;
        const delta = Math.min(rawDelta, 500) * this.timeScale; // cap delta, apply scale

        this._accumulator += delta;

        // Process full ticks
        while (this._accumulator >= this.tickIntervalMs) {
          this._accumulator -= this.tickIntervalMs;
          const tickEvents = this.objectEngine.tick(this.tickIntervalMs);
          this.tickCount++;
          this.elapsedMs += this.tickIntervalMs;

          this._wanderTick();

